import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toppingsList from '../toppings';

const BASE_PRICE   = 30;
const TOPPING_PRICE = 8;

export default function PizzaMenu() {
  const [selectedToppings, setSelectedToppings] = useState([]);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');

  const toggleTopping = t =>
    setSelectedToppings(prev =>
      prev.includes(t) ? prev.filter(x => x !== t) : [...prev, t]
    );

  const handleAddToCart = () => {
    localStorage.setItem('cart', JSON.stringify({
      toppings: selectedToppings,
      total: BASE_PRICE + selectedToppings.length * TOPPING_PRICE,
    }));
    navigate('/cart');
  };

  const total = BASE_PRICE + selectedToppings.length * TOPPING_PRICE;

  return (
    <div className="max-w-md mx-auto min-h-screen bg-white pb-20">

      {/* ── Header ── */}
      <div className="bg-white border-b border-gray-100 px-5 py-4 flex items-center relative">
        <div className="flex-1 text-center">
          <span className="font-black text-xl tracking-widest text-dark">PIZZA STORY</span>
        </div>
        {/* Cart badge */}
        <button
          onClick={() => navigate('/cart')}
          className="absolute left-4 relative"
        >
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
            stroke="#1A1A1A" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M6 2L3 6v14a2 2 0 002 2h14a2 2 0 002-2V6l-3-4z"/>
            <line x1="3" y1="6" x2="21" y2="6"/>
            <path d="M16 10a4 4 0 01-8 0"/>
          </svg>
          {cart.toppings && (
            <span
              className="absolute -top-1.5 -right-1.5 w-4 h-4 rounded-full flex items-center justify-center font-black text-dark"
              style={{ background: '#FFC107', fontSize: 9 }}
            >1</span>
          )}
        </button>
      </div>

      {/* ── Address strip ── */}
      <div className="bg-gray-50 px-5 py-2 flex items-center gap-2 border-b border-gray-100">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
          stroke="#9ca3af" strokeWidth="2" strokeLinecap="round">
          <path d="M21 10c0 7-9 13-9 13S3 17 3 10a9 9 0 0118 0z"/>
          <circle cx="12" cy="10" r="3"/>
        </svg>
        <span className="text-xs text-gray-400 flex-1">
          {auth.verified ? 'רחוב הפיצה 1, תל אביב' : 'הכנסו לשמירת כתובת'}
        </span>
        <span className="text-xs font-bold" style={{ color: '#22c55e' }}>● פתוח</span>
      </div>

      <div className="px-4 pt-4 space-y-4">

        {/* ── Hero Pizza Card ── */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
          <div className="relative">
            <img
              src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=500&q=80"
              alt="pizza"
              className="w-full h-52 object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/30 via-transparent to-transparent" />
            <div className="absolute bottom-3 right-3 flex gap-2">
              <span
                className="text-dark text-xs font-bold px-2.5 py-1 rounded-full"
                style={{ background: '#FFC107' }}
              >
                🕐 20–30 דק'
              </span>
            </div>
          </div>

          <div className="p-5">
            <div className="flex justify-between items-start mb-1">
              <div>
                <h2 className="font-black text-dark text-xl">פיצה קלאסית</h2>
                <p className="text-gray-400 text-sm mt-0.5">בצק טרי · רוטב ביתי · מוצרלה</p>
              </div>
              <span className="font-black text-dark text-2xl">{BASE_PRICE}₪</span>
            </div>

            {/* Divider */}
            <div className="border-t border-gray-100 my-4" />

            {/* ── Toppings ── */}
            <div className="mb-4">
              <div className="flex items-center justify-between mb-3">
                <span className="font-black text-dark text-sm">תוספות לבחירה</span>
                <span
                  className="text-xs font-bold text-dark px-2.5 py-1 rounded-full"
                  style={{ background: '#FFC10720', color: '#1A1A1A' }}
                >
                  +{TOPPING_PRICE}₪ לתוספת
                </span>
              </div>
              <div className="flex flex-wrap gap-2">
                {toppingsList.map(t => {
                  const active = selectedToppings.includes(t);
                  return (
                    <button
                      key={t}
                      onClick={() => toggleTopping(t)}
                      className="px-3 py-1.5 rounded-full text-sm font-semibold border transition select-none active:scale-95"
                      style={active
                        ? { background: '#FFC107', borderColor: '#FFC107', color: '#1A1A1A' }
                        : { background: 'white', borderColor: '#e5e7eb', color: '#6b7280' }
                      }
                    >
                      {t}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Price subtotal */}
            {selectedToppings.length > 0 && (
              <div className="flex justify-between items-center py-3 border-t border-b border-gray-100 mb-4 text-sm">
                <span className="text-gray-400">{selectedToppings.length} תוספות נבחרו</span>
                <span className="font-bold text-dark">סה"כ: {total}₪</span>
              </div>
            )}

            {/* ── CTA ── */}
            <button
              onClick={handleAddToCart}
              className="w-full font-black text-dark text-lg py-4 rounded-full flex items-center justify-between px-6 transition active:scale-95 shadow-sm"
              style={{ background: '#FFC107' }}
            >
              <span
                className="w-8 h-8 rounded-full bg-dark text-white flex items-center justify-center font-black text-xl"
              >+</span>
              <span>הוסף לסל</span>
              <span className="bg-black/10 px-3 py-1 rounded-full font-bold text-base">{total}₪</span>
            </button>
          </div>
        </div>

        {/* ── Login prompt (unauthenticated) ── */}
        {!auth.verified && (
          <button
            onClick={() => navigate('/login')}
            className="w-full bg-white border border-gray-200 rounded-2xl p-4 flex items-center gap-3 shadow-sm active:scale-95 transition"
          >
            <div
              className="w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0"
              style={{ background: '#FFC10720' }}
            >
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none"
                stroke="#1A1A1A" strokeWidth="2" strokeLinecap="round">
                <path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/>
                <circle cx="12" cy="7" r="4"/>
              </svg>
            </div>
            <div className="flex-1 text-right">
              <p className="font-bold text-dark text-sm">כנסו לחשבון</p>
              <p className="text-gray-400 text-xs">עקבו אחרי הזמנות ותוכנית נאמנות</p>
            </div>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none"
              stroke="#9ca3af" strokeWidth="2" strokeLinecap="round">
              <path d="M9 18l6-6-6-6"/>
            </svg>
          </button>
        )}
      </div>
    </div>
  );
}
